import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty array for empty input");
  it.todo("should kill a single live cell (underpopulation, 0 neighbors)");
  it.todo("should kill two adjacent live cells (underpopulation, 1 neighbor each)");
  it.todo("should keep a 2x2 block alive unchanged (still life)");
  it.todo("should let a live cell with 2 or 3 neighbors survive (survival)");
  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
  it.todo("should bring a dead cell with exactly 3 neighbors to life (reproduction)");
  it.todo("should oscillate a vertical blinker into a horizontal blinker");
  it.todo("should handle negative coordinates");
});
